6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This entity implements a full AXI master. In contrast to psi_common_axi_master_full,
11	-- this entity can do unaligned transfers and it supports different width for the
12	-- AXI interface than for the data interface. The AXI interface can be wider than
13	-- the data interface but not vice versa.
14	-- The flexibility of doing unaligned transfers is paid by lower performance for
15	-- very small transfers. There is an overhead of some clock cycles per command.
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.numeric_std.all;
20	
21	use work.psi_common_math_pkg.all;
22	use work.psi_common_logic_pkg.all;
23	
24	--@formatter:off
25	entity psi_common_axi_master_full is
26	  generic(
27	    axi_addr_width_g             : natural range 12 to 64  := 32;   -- Width of the AXI address bus
28	    axi_data_width_g             : natural range 8 to 1024 := 32;   -- Width of the AXI data bus
29	    axi_max_beats_g              : natural range 1 to 256  := 256;  -- Maximum number of beats in one AXI transaction. Values given by the AXI specification are 16 for AXI-3 and 256 for AXI-4. However, the user may choose any other number for scheduling reasons.
30	    axi_max_open_trasactions_g   : natural range 1 to 8    := 8;    -- Maximum number of AXI commands (AW/AR-channel) to send before the first command is completed (outstanding transactions).
31	    user_transaction_size_bits_g : natural                 := 32;   -- Number of bits used to specify the number of bytes to transfer on the user command interface. This is the only limiting factor for the transfer size requested.
32	    data_fifo_depth_g            : natural                 := 1024; -- Number of entries in the read/write data FIFOs (user side)
33	    axi_fifo_depth_g             : natural                 := 512;  -- Number of entries in the FIFOs inside the AXI interface
34	    data_width_g                 : natural                 := 32;   -- Width of the user data interface
35	    impl_read_g                  : boolean                 := true; -- Implement read functionality (can be disabled to save resources)
36	    impl_write_g                 : boolean                 := true; -- Implement write functionality (can be disabled to save resources)
37	    ram_behavior_g               : string                  := "RBW" --  Block-RAM style (must match FPGA architecture),**"RBW"** Read before write,**"WBR"** Write
38	  );
39	  port(
40	    -- Control Signals
41	    m_axi_aclk       : in  std_logic;                                                                       -- AXI clock
42	    m_axi_aresetn    : in  std_logic;                                                                       -- AXI resetn
43	    -- User Command Interface
44	    cmd_wr_addr_i    : in  std_logic_vector(axi_addr_width_g - 1 downto 0)             := (others => '0');  -- Address to start writing at (must be aligned)
45	    cmd_wr_size_i    : in  std_logic_vector(user_transaction_size_bits_g - 1 downto 0) := (others => '0');  -- Number of bytes in the transfer
46	    cmd_wr_low_lat_i : in  std_logic                                                   := '0';              -- **'1'** \--\> Low latency mode, **'0'** \--\> High latency mode
47	    cmd_wr_vld_i     : in  std_logic                                                   := '0';              -- AXI-S handshaking signal
48	    cmd_wr_rdy_o     : out std_logic;                                                                       -- AXI-S handshaking signal
49	    -- User Command Interface
50	    cmd_rd_addr_i    : in  std_logic_vector(axi_addr_width_g - 1 downto 0)             := (others => '0');  -- Address to start reading at (must be aligned)
51	    cmd_rd_size_o    : in  std_logic_vector(user_transaction_size_bits_g - 1 downto 0) := (others => '0');  -- Number of bytes in the transfer
52	    cmd_rd_low_lat_i : in  std_logic                                                   := '0';              -- **'1'** \--\> Low latency mode, **'0'** \--\> High latency mode
53	    cmd_rd_vld_i     : in  std_logic                                                   := '0';              -- AXI-S handshaking signal
54	    cmd_rd_rdy_o     : out std_logic;                                                                       -- AXI-S handshaking signal
55	    -- Write Data
56	    wr_dat_i         : in  std_logic_vector(data_width_g - 1 downto 0)                 := (others => '0');  -- Write data (right-aligned)
57	    wr_vld_i         : in  std_logic                                                   := '0';              -- AXI-S handshaking signal
58	    wr_rdy_o         : out std_logic;                                                                       -- AXI-S handshaking signal
59	    -- Read Data
60	    rd_dat_o         : out std_logic_vector(data_width_g - 1 downto 0);                                     -- Read data (right-aligned)
61	    rd_vld_o         : out std_logic;                                                                       -- AXI-S handshaking signal
62	    rd_rdy_i         : in  std_logic                                                   := '0';              -- AXI-S handshaking signal
63	    -- Response
64	    wr_done_o        : out std_logic;                                                                       -- Write command was completed successfully
65	    wr_error_o       : out std_logic;                                                                       -- Write command was completed but at least one transaction failed (AXI response from slave indicated an error)
66	    rd_done_o        : out std_logic;                                                                       -- Read command was completed successfully
67	    rd_error_o       : out std_logic;                                                                       -- Read command was completed but at least one transaction failed
68	    -- AXI Address Write Channel
69	    m_axi_awaddr     : out std_logic_vector(axi_addr_width_g - 1 downto 0); 
70	    m_axi_awlen      : out std_logic_vector(7 downto 0); 
71	    m_axi_awsize     : out std_logic_vector(2 downto 0); 
72	    m_axi_awburst    : out std_logic_vector(1 downto 0); 
73	    m_axi_awlock     : out std_logic;
74	    m_axi_awcache    : out std_logic_vector(3 downto 0); 
75	    m_axi_awprot     : out std_logic_vector(2 downto 0); 
76	    m_axi_awvalid    : out std_logic;
77	    m_axi_awready    : in  std_logic                                                   := '0'; 
78	    -- AXI Write Data Channel                                                           				
79	    m_axi_wdata      : out std_logic_vector(axi_data_width_g - 1 downto 0);
80	    m_axi_wstrb      : out std_logic_vector(axi_data_width_g / 8 - 1 downto 0);
81	    m_axi_wlast      : out std_logic;
82	    m_axi_wvalid     : out std_logic;
83	    m_axi_wready     : in  std_logic                                                   := '0'; 
84	    -- AXI Write Response Channel
85	    m_axi_bresp      : in  std_logic_vector(1 downto 0)                                := (others => '0'); 
86	    m_axi_bvalid     : in  std_logic                                                   := '0'; 
87	    m_axi_bready     : out std_logic;  
88	    -- AXI Read Address Channel
89	    m_axi_araddr     : out std_logic_vector(axi_addr_width_g - 1 downto 0); 
90	    m_axi_arlen      : out std_logic_vector(7 downto 0); 
91	    m_axi_arsize     : out std_logic_vector(2 downto 0); 
92	    m_axi_arburst    : out std_logic_vector(1 downto 0);
93	    m_axi_arlock     : out std_logic; 
94	    m_axi_arcache    : out std_logic_vector(3 downto 0); 
95	    m_axi_arprot     : out std_logic_vector(2 downto 0); 
96	    m_axi_arvalid    : out std_logic;
97	    m_axi_arready    : in  std_logic                                                   := '0'; 
98	    -- AXI Read Data Channel
99	    m_axi_rdata      : in  std_logic_vector(axi_data_width_g - 1 downto 0)             := (others => '0'); 
100	    m_axi_rresp      : in  std_logic_vector(1 downto 0)                                := (others => '0'); 
101	    m_axi_rlast      : in  std_logic                                                   := '0'; 
102	    m_axi_rvalid     : in  std_logic                                                   := '0'; 
103	    m_axi_rready     : out std_logic
104	  );
105	end entity;
106	--@formatter:on
107	
108	architecture rtl of psi_common_axi_master_full is
109	
110	  ------------------------------------------------------------------------------
111	  -- Constants
112	  ------------------------------------------------------------------------------
113	  constant AxiBytes_c   : natural := axi_data_width_g / 8;
114	  constant DataBytes_c  : natural := data_width_g / 8;
115	
116	  ------------------------------------------------------------------------------
117	  -- Type
118	  ------------------------------------------------------------------------------
119	  type WriteCmdFsm_t is (Idle_s, Apply_s);
120	  type WriteWconvFsm_t is (Idle_s, Transfer_s);
121	  type WriteAlignFsm_t is (Idle_s, Transfer_s, Last_s);
122	  type ReadCmdFsm_t is (Idle_s, Apply_s, WaitDataFsm_s);
123	  type ReadDataFsm_t is (Idle_s, Transfer_s, Wait_s);
124	
125	  ------------------------------------------------------------------------------
126	  -- Functions
127	  ------------------------------------------------------------------------------
128	  function AlignedAddr_f(Addr : in unsigned(axi_addr_width_g-1 downto 0))
129	  return unsigned is
130	    variable Addr_v : unsigned(Addr'range) := (others => '0');
131	  begin
132	    Addr_v(Addr'left downto log2(AxiBytes_c)) := Addr(Addr'left downto log2(AxiBytes_c));
133	    return Addr_v;
134	  end function;
135	
136	  ------------------------------------------------------------------------------
137	  -- Two Process Record
138	  ------------------------------------------------------------------------------
139	  type two_process_r is record
140	
141	    -- *** Write Related Registers ***
142	    WrCmdFsm        : WriteCmdFsm_t;
143	    WrLastAddr      : unsigned(axi_addr_width_g - 1 downto 0);
144	    cmd_wr_rdy_o    : std_logic;
145	    AxiWrCmd_Addr   : std_logic_vector(axi_addr_width_g - 1 downto 0);
146	    AxiWrCmd_Size   : std_logic_vector(user_transaction_size_bits_g - 1 downto 0);
147	    WrAlignCmdSize  : std_logic_vector(user_transaction_size_bits_g - 1 downto 0);
148	    AxiWrCmd_LowLat : std_logic;
149	    AxiWrCmd_Vld    : std_logic;
150	    WrWconvFsm      : WriteWconvFsm_t;
151	    WrStartTf       : std_logic;
152	    WrWordsDone     : unsigned(user_transaction_size_bits_g - 1 downto 0);
153	    WrDataWordsCmd  : unsigned(user_transaction_size_bits_g - 1 downto 0);
154	    WrDataWordsWc   : unsigned(user_transaction_size_bits_g - 1 downto 0);
155	    WrAlignFsm      : WriteAlignFsm_t;
156	    WrAlignReg      : std_logic_vector(axi_data_width_g * 2 - 1 downto 0);
157	    WrAlignBe       : std_logic_vector(AxiBytes_c * 2 - 1 downto 0);
158	    WrShift         : unsigned(log2(AxiBytes_c) - 1 downto 0);
159	    WrAlignShift    : unsigned(log2(AxiBytes_c) - 1 downto 0);
160	    WrAlignVld      : std_logic;
161	    AxiWordCnt      : unsigned(user_transaction_size_bits_g - 1 downto 0);
162	    WrLastBe        : std_logic_vector(AxiBytes_c - 1 downto 0);
163	    WrAlignLastBe   : std_logic_vector(AxiBytes_c - 1 downto 0);
164	    WrAlignLast     : std_logic;
165	
166	    -- *** Read Related Registers ***
167	    RdCmdFsm        : ReadCmdFsm_t;
168	    RdLastAddr      : unsigned(axi_addr_width_g - 1 downto 0);
169	    RdFirstAddrOffs : unsigned(log2(AxiBytes_c) - 1 downto 0);
170	    cmd_rd_rdy_o    : std_logic;
171	    AxiRdCmd_Addr   : std_logic_vector(axi_addr_width_g - 1 downto 0);
172	    AxiRdCmd_LowLat : std_logic;
173	    AxiRdCmd_Vld    : std_logic;
174	    AxiRdCmd_Size   : std_logic_vector(user_transaction_size_bits_g - 1 downto 0);
175	    RdFirstBe       : std_logic_vector(AxiBytes_c - 1 downto 0);
176	    RdLastBe        : std_logic_vector(AxiBytes_c - 1 downto 0);
177	    RdDataFsm       : ReadDataFsm_t;
178	    RdStartTf       : std_logic;
179	    RdDataEna       : std_logic;
180	    RdDatFirstBe    : std_logic_vector(AxiBytes_c - 1 downto 0);
181	    RdDatLastBe     : std_logic_vector(AxiBytes_c - 1 downto 0);
182	    RdDataWords     : unsigned(user_transaction_size_bits_g - 1 downto 0);
183	    RdCurrentWord   : unsigned(user_transaction_size_bits_g - 1 downto 0);
184	    RdShift         : unsigned(log2(AxiBytes_c) - 1 downto 0);
185	    RdLowIdx        : unsigned(log2(AxiBytes_c) downto 0);
186	    RdAlignShift    : unsigned(log2(AxiBytes_c) - 1 downto 0);
187	    RdAlignLowIdx   : unsigned(log2(AxiBytes_c) downto 0);
188	    RdAlignByteVld  : std_logic_vector(AxiBytes_c * 2 - 1 downto 0);
189	    RdAlignReg      : std_logic_vector(axi_data_width_g * 2 - 1 downto 0);
190	    RdAlignLast     : std_logic;
191	  end record;
192	  signal r, r_next : two_process_r;
193	
194	  ------------------------------------------------------------------------------
195	  -- Instantiation Signals
196	  ------------------------------------------------------------------------------
197	  signal WrFifo_Data   : std_logic_vector(wr_dat_i'range);
198	  signal WrFifo_Vld    : std_logic;
199	  signal AxiWrCmd_Rdy  : std_logic;
200	  signal AxiWrDat_Rdy  : std_logic;
201	  signal AxiWrDat_Data : std_logic_vector(axi_data_width_g - 1 downto 0);
202	  signal WrFifo_Rdy    : std_logic;
203	  signal AxiWrDat_Be   : std_logic_vector(AxiBytes_c - 1 downto 0);
204	  signal WrWconvEna    : std_logic;
205	  signal WrWconv_Vld   : std_logic;
206	  signal WrWconv_Rdy   : std_logic;
207	  signal WrWconv_Last  : std_logic;
208	  signal WrData_Vld    : std_logic;
209	  signal WrData_Data   : std_logic_vector(axi_data_width_g - 1 downto 0);
210	  signal WrData_Last   : std_logic;
211	  signal WrData_We     : std_logic_vector(AxiBytes_c / DataBytes_c - 1 downto 0);
212	  signal WrData_Rdy    : std_logic;
213	  signal WrDataEna     : std_logic;
214	  signal AxiRdCmd_Rdy  : std_logic;
215	  signal AxiRdDat_Rdy  : std_logic;
216	  signal AxiRdDat_Vld  : std_logic;
217	  signal AxiRdDat_Data : std_logic_vector(axi_data_width_g - 1 downto 0);
218	  signal RdFifo_Rdy    : std_logic;
219	  signal RdFifo_Data   : std_logic_vector(data_width_g - 1 downto 0);
220	  signal RdFifo_Vld    : std_logic;
221	
222	begin
223	
224	  ------------------------------------------------------------------------------
225	  -- Assertions
226	  ------------------------------------------------------------------------------
227	  assert axi_data_width_g mod 8 = 0 report "###ERROR###: psi_common_axi_master_full axi_data_width_g must be a multiple of 8" severity failure;
228	  assert data_width_g mod 8 = 0 report "###ERROR###: psi_common_axi_master_full data_width_g must be a multiple of 8" severity failure;
229	  assert axi_data_width_g mod data_width_g = 0 report "###ERROR###: psi_common_axi_master_full axi_data_width_g must be a multiple of data_width_g" severity failure;
230	
231	  ------------------------------------------------------------------------------
232	  -- Combinatorial Process
233	  ------------------------------------------------------------------------------
234	  p_comb : process(r, cmd_wr_addr_i, cmd_wr_size_i, cmd_wr_vld_i, cmd_wr_low_lat_i, cmd_rd_addr_i, cmd_rd_size_o, cmd_rd_vld_i, cmd_rd_low_lat_i, AxiWrCmd_Rdy, AxiWrDat_Rdy, AxiRdCmd_Rdy, AxiRdDat_Vld, AxiRdDat_Data, WrWconv_Rdy, WrFifo_Vld, WrData_Vld, WrData_Data, WrData_Last, WrData_We, RdFifo_Rdy)
235	    variable v              : two_process_r;
236	    variable WriteBe_v      : std_logic_vector(AxiBytes_c - 1 downto 0);
237	    variable RdAlignReady_v : std_logic;
238	    variable RdLowIdxInt_v  : integer range 0 to AxiBytes_c;
239	    variable RdDatBe_v      : std_logic_vector(AxiBytes_c - 1 downto 0);
240	    variable RdDataLast_v   : std_logic;
241	  begin
242	    -- *** Keep two process variables stable ***
243	    v := r;
244	
245	    --------------------------------------------------------------------------
246	    -- Write Related Code
247	    --------------------------------------------------------------------------
248	    if impl_write_g then
249	
250	      -- *** Command FSM ***
251	      v.WrStartTf    := '0';
252	      v.AxiWrCmd_Vld := '0';
253	      case r.WrCmdFsm is
254	
255	        when Idle_s =>
256	          v.cmd_wr_rdy_o    := '1';
257	          v.WrLastAddr      := unsigned(cmd_wr_addr_i) + unsigned(cmd_wr_size_i) - 1;
258	          if unsigned(cmd_wr_size_i(log2(DataBytes_c) - 1 downto 0)) = 0 then
259	            v.WrDataWordsCmd := resize(unsigned(cmd_wr_size_i(cmd_wr_size_i'high downto log2(DataBytes_c))), user_transaction_size_bits_g);
260	          else
261	            v.WrDataWordsCmd := resize(unsigned(cmd_wr_size_i(cmd_wr_size_i'high downto log2(DataBytes_c))) + 1, user_transaction_size_bits_g);
262	          end if;
263	          v.AxiWrCmd_Addr   := std_logic_vector(AlignedAddr_f(unsigned(cmd_wr_addr_i)));
264	          v.WrShift         := unsigned(cmd_wr_addr_i(v.WrShift'range));
265	          v.AxiWrCmd_LowLat := cmd_wr_low_lat_i;
266	          if cmd_wr_vld_i = '1' then
267	            v.cmd_wr_rdy_o := '0';
268	            v.WrCmdFsm     := Apply_s;
269	          end if;
270	
271	        when Apply_s =>
272	          if (AxiWrCmd_Rdy = '1') and (r.WrWconvFsm = Idle_s) and (r.WrAlignFsm = Idle_s) then
273	            v.AxiWrCmd_Vld  := '1';
274	            v.WrStartTf     := '1';
275	            v.WrCmdFsm      := Idle_s;
276	            v.cmd_wr_rdy_o  := '1';
277	            v.AxiWrCmd_Size := std_logic_vector(resize(shift_right(AlignedAddr_f(r.WrLastAddr) - unsigned(r.AxiWrCmd_Addr), log2(AxiBytes_c)) + 1, user_transaction_size_bits_g));
278	            -- Calculate byte enables for last word
279	            for byte in 0 to AxiBytes_c - 1 loop
280	              if r.WrLastAddr(log2(AxiBytes_c) - 1 downto 0) >= byte then
281	                v.WrLastBe(byte) := '1';
282	              else
283	                v.WrLastBe(byte) := '0';
284	              end if;
285	            end loop;
286	          end if;
287	
288	        when others => null;
289	
290	      end case;
291	
292	      -- *** With Conversion FSM ***
293	      WrWconvEna   <= '0';
294	      WrWconv_Last <= '0';
295	      case r.WrWconvFsm is
296	
297	        -- Latch values that change for the next command that may be interpreted while the current one is running
298	        when Idle_s =>
299	          v.WrWordsDone   := to_unsigned(1, v.WrWordsDone'length);
300	          v.WrDataWordsWc := r.WrDataWordsCmd;
301	          if r.WrStartTf = '1' then
302	            v.WrWconvFsm := Transfer_s;
303	          end if;
304	
305	        -- Execute transfer
306	        when Transfer_s =>
307	          WrWconvEna <= '1';
308	          if r.WrWordsDone = r.WrDataWordsWc then
309	            WrWconv_Last <= '1';
310	          end if;
311	          if (WrWconv_Rdy = '1') and (WrFifo_Vld = '1') then
312	            v.WrWordsDone := r.WrWordsDone + 1;
313	            if r.WrWordsDone = r.WrDataWordsWc then
314	              v.WrWconvFsm := Idle_s;
315	            end if;
316	          end if;
317	
318	        when others => null;
319	      end case;
320	
321	      -- *** Alignment FSM ***
322	      -- Initial values
323	      WrDataEna <= '0';
324	      --v.WrAlignVld := '0';
325	      -- Word- to Byte-Enable conversion
326	      for i in 0 to AxiBytes_c - 1 loop
327	        WriteBe_v(i) := WrData_We(i / data_width_g);
328	      end loop;
329	      -- FSM
330	      case r.WrAlignFsm is
331	
332	        -- Latch values that change for the next command that may be interpreted while the current one is running
333	        when Idle_s =>
334	          v.WrAlignReg     := (others => '0');
335	          v.WrAlignBe      := (others => '0');
336	          v.AxiWordCnt     := to_unsigned(1, v.AxiWordCnt'length);
337	          v.WrAlignLast    := '0';
338	          v.WrAlignShift   := r.WrShift;
339	          v.WrAlignCmdSize := r.AxiWrCmd_Size;
340	          v.WrAlignLastBe  := r.WrLastBe;
341	          v.WrAlignVld     := '0';
342	          if r.WrStartTf = '1' then
343	            v.WrAlignFsm := Transfer_s;
344	          end if;
345	
346	        -- Move data from the FIFO to AXI
347	        when Transfer_s =>
348	          WrDataEna <= '1';
349	          if (AxiWrDat_Rdy = '1') and ((WrData_Vld = '1') or (r.WrAlignLast = '1')) then
350	            -- Don't add new byte enables on last data flushing
351	            if r.WrAlignLast = '1' then
352	              WriteBe_v := (others => '0');
353	            end if;
354	            -- Shift
355	            v.WrAlignReg(axi_data_width_g - 1 downto 0)                                                           := r.WrAlignReg(r.WrAlignReg'left downto axi_data_width_g);
356	            v.WrAlignBe(AxiBytes_c - 1 downto 0)                                                                  := r.WrAlignBe(r.WrAlignBe'left downto AxiBytes_c);
357	            -- New Data
358	            v.WrAlignReg((to_integer(r.WrAlignShift) + AxiBytes_c) * 8 - 1 downto to_integer(r.WrAlignShift) * 8) := WrData_Data;
359	            v.WrAlignBe(to_integer(r.WrAlignShift) + AxiBytes_c - 1 downto to_integer(r.WrAlignShift))            := WriteBe_v;
360	            -- Flow control
361	            v.WrAlignVld                                                                                          := '1';
362	            if r.AxiWordCnt = unsigned(r.WrAlignCmdSize) then
363	              v.WrAlignFsm                         := Last_s;
364	              v.WrAlignBe(AxiBytes_c - 1 downto 0) := v.WrAlignBe(AxiBytes_c - 1 downto 0) and r.WrAlignLastBe;
365	            end if;
366	            v.AxiWordCnt                                                                                          := r.AxiWordCnt + 1;
367	            -- Force last data out
368	            v.WrAlignLast                                                                                         := WrData_Last;
369	          elsif AxiWrDat_Rdy = '1' then
370	            v.WrAlignVld := '0';
371	          end if;
372	
373	        -- Wait for the last beat te be accepted without reading more data from the FIFO
374	        when Last_s =>
375	          v.WrAlignVld := '1';
376	          if AxiWrDat_Rdy = '1' then
377	            v.WrAlignVld := '0';
378	            v.WrAlignFsm := Idle_s;
379	          end if;
380	
381	        when others => null;
382	      end case;
383	    end if;
384	
385	    --------------------------------------------------------------------------
386	    -- Read Related Code
387	    --------------------------------------------------------------------------
388	    if impl_read_g then
389	
390	      -- *** Variables ***
391	      RdLowIdxInt_v  := to_integer(r.RdAlignLowIdx);
392	      RdAlignReady_v := r.RdDataEna;
393	      -- Vivado workaround
394	      for i in 0 to AxiBytes_c loop
395	        if i = RdLowIdxInt_v then
396	          -- no new data fits into shifter, even if output is ready. This only happens for user width < axi width
397	          if (DataBytes_c < AxiBytes_c) and (unsigned(r.RdAlignByteVld(r.RdAlignByteVld'high downto i + DataBytes_c)) /= 0) then
398	            RdAlignReady_v := '0';
399	          -- if output is ready, new data can be accepted (back-to-back)
400	          elsif unsigned(r.RdAlignByteVld(r.RdAlignByteVld'high downto i)) /= 0 and RdFifo_Rdy = '0' then
401	            RdAlignReady_v := '0';
402	          end if;
403	        end if;
404	      end loop;
405	
406	      -- *** Command FSM ***
407	      v.RdStartTf    := '0';
408	      v.AxiRdCmd_Vld := '0';
409	      case r.RdCmdFsm is
410	
411	        when Idle_s =>
412	
413	          v.cmd_rd_rdy_o    := '1';
414	          v.RdLastAddr      := unsigned(cmd_rd_addr_i) + unsigned(cmd_rd_size_o) - 1;
415	          v.RdFirstAddrOffs := unsigned(cmd_rd_addr_i(v.RdFirstAddrOffs'range));
416	          v.AxiRdCmd_Addr   := std_logic_vector(AlignedAddr_f(unsigned(cmd_rd_addr_i)));
417	          v.AxiRdCmd_LowLat := cmd_rd_low_lat_i;
418	          v.RdShift         := unsigned(cmd_rd_addr_i(v.RdShift'range));
419	          v.RdLowIdx        := to_unsigned(AxiBytes_c, v.RdLowIdx'length) - unsigned(cmd_rd_addr_i(v.RdShift'range));
420	          if cmd_rd_vld_i = '1' then
421	            v.cmd_rd_rdy_o := '0';
422	            v.RdCmdFsm     := Apply_s;
423	          end if;
424	
425	        when Apply_s =>
426	          -- AXI command can be sent early
427	          if (AxiRdCmd_Rdy = '1') then
428	            v.AxiRdCmd_Vld  := '1';
429	            v.RdCmdFsm      := WaitDataFsm_s;
430	            v.RdStartTf     := '1';
431	            v.AxiRdCmd_Size := std_logic_vector(resize(shift_right(AlignedAddr_f(r.RdLastAddr) - unsigned(r.AxiRdCmd_Addr), log2(AxiBytes_c)) + 1, user_transaction_size_bits_g));
432	            -- Calculate byte enables for last byte
433	            for byte in 0 to AxiBytes_c - 1 loop
434	              if r.RdLastAddr(log2(AxiBytes_c) - 1 downto 0) >= byte then
435	                v.RdLastBe(byte) := '1';
436	              else
437	                v.RdLastBe(byte) := '0';
438	              end if;
439	            end loop;
440	            -- Calculate byte enables for first byte
441	            for byte in 0 to AxiBytes_c - 1 loop
442	              if r.RdFirstAddrOffs <= byte then
443	                v.RdFirstBe(byte) := '1';
444	              else
445	                v.RdFirstBe(byte) := '0';
446	              end if;
447	            end loop;
448	          end if;
449	
450	        -- Start data FSM before sending next command to avoid owerwriting data before it was latched
451	        when WaitDataFsm_s =>
452	          v.RdStartTf := '1';
453	          if r.RdDataFsm = Idle_s then
454	            v.RdCmdFsm     := Idle_s;
455	            v.cmd_rd_rdy_o := '1';
456	            v.RdStartTf    := '0';
457	          end if;
458	
459	        when others => null;
460	      end case;
461	
462	      -- *** Data FSM ***
463	      v.RdDataEna  := '0';
464	      RdDatBe_v    := (others => '1');
465	      RdDataLast_v := '0';
466	      case r.RdDataFsm is
467	
468	        when Idle_s =>
469	          v.RdDatFirstBe  := r.RdFirstBe;
470	          v.RdDatLastBe   := r.RdLastBe;
471	          v.RdDataWords   := unsigned(r.AxiRdCmd_Size);
472	          v.RdCurrentWord := to_unsigned(1, v.RdCurrentWord'length);
473	          v.RdAlignShift  := r.RdShift;
474	          v.RdAlignLowIdx := r.RdLowIdx;
475	          if r.RdStartTf = '1' then
476	            v.RdDataFsm := Transfer_s;
477	            v.RdDataEna := '1';
478	          end if;
479	
480	        when Transfer_s =>
481	          v.RdDataEna := '1';
482	          if r.RdCurrentWord = 1 then
483	            RdDatBe_v := RdDatBe_v and r.RdDatFirstBe;
484	          end if;
485	          if r.RdCurrentWord = r.RdDataWords then
486	            RdDatBe_v    := RdDatBe_v and r.RdDatLastBe;
487	            RdDataLast_v := '1';
488	          end if;
489	          if (RdAlignReady_v = '1') and (AxiRdDat_Vld = '1') and (r.RdDataEna = '1') then
490	            v.RdCurrentWord := r.RdCurrentWord + 1;
491	            if r.RdCurrentWord = r.RdDataWords then
492	              v.RdDataEna := '0';
493	              v.RdDataFsm := Wait_s;
494	            end if;
495	          end if;
496	
497	        -- Wait until reception of all data is done
498	        when Wait_s =>
499	          if unsigned(r.RdAlignByteVld) = 0 then
500	            v.RdDataFsm := Idle_s;
501	          end if;
502	
503	        when others => null;
504	      end case;
505	
506	      -- *** Data Alignment ***
507	      AxiRdDat_Rdy <= RdAlignReady_v;
508	      RdFifo_Vld   <= '0';
509	      -- shift
510	      if (RdFifo_Rdy = '1') and (RdAlignReady_v = '0' or AxiRdDat_Vld = '1' or r.RdAlignLast = '1') then
511	        -- Shift is only done if data can be consumed (RdFifo_Rdy) and either no new data is required for the next shift (RdAlignReady_v = '0'),
512	        -- .. the data is available (AxiRdDat_Vld = '1') or we are at the end of a transfer (r.RdAlignLast = '1')
513	        v.RdAlignReg     := zeros_vector(data_width_g) & r.RdAlignReg(r.RdAlignReg'left downto data_width_g);
514	        v.RdAlignByteVld := zeros_vector(DataBytes_c) & r.RdAlignByteVld(r.RdAlignByteVld'left downto DataBytes_c);
515	        if r.RdAlignLast = '1' then
516	          RdFifo_Vld <= reduce_or(r.RdAlignByteVld(DataBytes_c - 1 downto 0));
517	        else
518	          RdFifo_Vld <= reduce_and(r.RdAlignByteVld(DataBytes_c - 1 downto 0));
519	        end if;
520	      end if;
521	      -- get new data
522	      if RdAlignReady_v = '1' and AxiRdDat_Vld = '1' then
523	        v.RdAlignReg(RdLowIdxInt_v * 8 + axi_data_width_g - 1 downto RdLowIdxInt_v * 8) := AxiRdDat_Data;
524	        v.RdAlignByteVld(RdLowIdxInt_v + AxiBytes_c - 1 downto RdLowIdxInt_v)           := RdDatBe_v;
525	        v.RdAlignLast                                                                   := RdDataLast_v;
526	      end if;
527	
528	      -- Send data to FIFO
529	      RdFifo_Data <= r.RdAlignReg(data_width_g - 1 downto 0);
530	
531	    end if;
532	
533	    -- *** Update Signal ***
534	    r_next <= v;
535	  end process;
536	
537	  ------------------------------------------------------------------------------
538	  -- Registered Process
539	  ------------------------------------------------------------------------------
540	  p_reg : process(m_axi_aclk)
541	  begin
542	    if rising_edge(m_axi_aclk) then
543	      r <= r_next;
544	      if m_axi_aresetn = '0' then
545	        -- *** Write Related Registers ***
546	        if impl_write_g then
547	          r.WrCmdFsm     <= Idle_s;
548	          r.cmd_wr_rdy_o <= '0';
549	          r.AxiWrCmd_Vld <= '0';
550	          r.WrWconvFsm   <= Idle_s;
551	          r.WrStartTf    <= '0';
552	          r.WrAlignFsm   <= Idle_s;
553	          r.WrAlignVld   <= '0';
554	        end if;
555	        -- *** Read Related Registers ***
556	        if impl_read_g then
557	          r.RdCmdFsm       <= Idle_s;
558	          r.cmd_rd_rdy_o   <= '0';
559	          r.AxiRdCmd_Vld   <= '0';
560	          r.RdDataFsm      <= Idle_s;
561	          r.RdStartTf      <= '0';
562	          r.RdDataEna      <= '0';
563	          r.RdAlignByteVld <= (others => '0');
564	        end if;
565	      end if;
566	    end if;
567	  end process;
568	
569	  ------------------------------------------------------------------------------
570	  -- Outputs
571	  ------------------------------------------------------------------------------
572	  cmd_wr_rdy_o <= r.cmd_wr_rdy_o;
573	  cmd_rd_rdy_o <= r.cmd_rd_rdy_o;
574	
575	  -- AXI Master Interface
576	  AxiWrDat_Data <= r.WrAlignReg(AxiWrDat_Data'range);
577	  AxiWrDat_Be   <= r.WrAlignBe(AxiWrDat_Be'range);
578	  i_axi : entity work.psi_common_axi_master_simple
579	    generic map(
580	      axi_addr_width_g             => axi_addr_width_g,
581	      axi_data_width_g             => axi_data_width_g,
582	      axi_max_beats_g              => axi_max_beats_g,
583	      axi_max_open_transactions_g  => axi_max_open_trasactions_g,
584	      user_transaction_size_bits_g => user_transaction_size_bits_g,
585	      data_fifo_depth_g            => axi_fifo_depth_g,
586	      impl_read_g                  => impl_read_g,
587	      impl_write_g                 => impl_write_g,
588	      ram_behavior_g               => ram_behavior_g)
589	    port map(
590	      -- Control Signals
591	      m_axi_aclk       => m_axi_aclk,
592	      m_axi_aresetn    => m_axi_aresetn,
593	      -- User Command Interface
594	      cmd_wr_addr_i    => r.AxiWrCmd_Addr,
595	      cmd_wr_size_i    => r.AxiWrCmd_Size,
596	      cmd_wr_low_lat_i => r.AxiWrCmd_LowLat,
597	      cmd_wr_vld_i     => r.AxiWrCmd_Vld,
598	      cmd_wr_rdy_o     => AxiWrCmd_Rdy,
599	      -- User Command Interface
600	      cmd_rd_addr_i    => r.AxiRdCmd_Addr,
601	      cmd_rd_size_o    => r.AxiRdCmd_Size,
602	      cmd_rd_low_lat_i => r.AxiRdCmd_LowLat,
603	      cmd_rd_vld_i     => r.AxiRdCmd_Vld,
604	      cmd_rd_rdy_o     => AxiRdCmd_Rdy,
605	      -- Write Data
606	      wr_dat_i         => AxiWrDat_Data,
607	      wr_data_be_i     => AxiWrDat_Be,
608	      wr_vld_i         => r.WrAlignVld,
609	      wr_rdy_o         => AxiWrDat_Rdy,
610	      -- Read Data
611	      rd_dat_o         => AxiRdDat_Data,
612	      rd_vld_o         => AxiRdDat_Vld,
613	      rd_rdy_i         => AxiRdDat_Rdy,
614	      -- Response
615	      wr_done_o        => wr_done_o,
616	      wr_error_o       => wr_error_o,
617	      rd_done_o        => rd_done_o,
618	      rd_error_o       => rd_error_o,
619	      -- AXI Address Write Channel
620	      m_axi_awaddr     => m_axi_awaddr,
621	      m_axi_awlen      => m_axi_awlen,
622	      m_axi_awsize     => m_axi_awsize,
623	      m_axi_awburst    => m_axi_awburst,
624	      m_axi_awlock     => m_axi_awlock,
625	      m_axi_awcache    => m_axi_awcache,
626	      m_axi_awprot     => m_axi_awprot,
627	      m_axi_awvalid    => m_axi_awvalid,
628	      m_axi_awready    => m_axi_awready,
629	      -- AXI Write Data Channel
630	      m_axi_wdata      => m_axi_wdata,
631	      m_axi_wstrb      => m_axi_wstrb,
632	      m_axi_wlast      => m_axi_wlast,
633	      m_axi_wvalid     => m_axi_wvalid,
634	      m_axi_wready     => m_axi_wready,
635	      -- AXI Write Response Channel
636	      m_axi_bresp      => m_axi_bresp,
637	      m_axi_bvalid     => m_axi_bvalid,
638	      m_axi_bready     => m_axi_bready,
639	      -- AXI Read Address Channel
640	      m_axi_araddr     => m_axi_araddr,
641	      m_axi_arlen      => m_axi_arlen,
642	      m_axi_arsize     => m_axi_arsize,
643	      m_axi_arburst    => m_axi_arburst,
644	      m_axi_arlock     => m_axi_arlock,
645	      m_axi_arcache    => m_axi_arcache,
646	      m_axi_arprot     => m_axi_arprot,
647	      m_axi_arvalid    => m_axi_arvalid,
648	      m_axi_arready    => m_axi_arready,
649	      -- AXI Read Data Channel
650	      m_axi_rdata      => m_axi_rdata,
651	      m_axi_rresp      => m_axi_rresp,
652	      m_axi_rlast      => m_axi_rlast,
653	      m_axi_rvalid     => m_axi_rvalid,
654	      m_axi_rready     => m_axi_rready);
655	
656	  -- *** Write Releated Code ***
657	  g_write : if impl_write_g generate
658	
659	    -- Write Data FIFO
660	    WrFifo_Rdy <= WrWconv_Rdy and WrWconvEna;
661	    i_fifo_wr_data : entity work.psi_common_sync_fifo
662	      generic map(
663	        width_g        => data_width_g,
664	        depth_g        => data_fifo_depth_g,
665	        alm_full_on_g  => false,
666	        alm_empty_on_g => false,
667	        ram_style_g    => "auto",
668	        ram_behavior_g => ram_behavior_g,
669	        rst_pol_g      => '0'
670	      )
671	      port map(
672	        clk_i => m_axi_aclk,
673	        rst_i => m_axi_aresetn,
674	        dat_i => wr_dat_i,
675	        vld_i => wr_vld_i,
676	        rdy_o => wr_rdy_o,
677	        dat_o => WrFifo_Data,
678	        vld_o => WrFifo_Vld,
679	        rdy_i => WrFifo_Rdy
680	      );
681	
682	    -- Write Data With Conversion
683	    WrWconv_Vld <= WrWconvEna and WrFifo_Vld;
684	    WrData_Rdy  <= AxiWrDat_Rdy and WrDataEna;
685	    i_wc_wr : entity work.psi_common_wconv_n2xn
686	      generic map( width_in_g  => data_width_g,
687	                   width_out_g => axi_data_width_g,
688	                   rst_pol_g   => '0')
689	      port map(    clk_i     => m_axi_aclk,
690	                   rst_i     => m_axi_aresetn,
691	                   vld_i     => WrWconv_Vld,
692	                   rdy_o  => WrWconv_Rdy,
693	                   dat_i     => WrFifo_Data,
694	                   last_i    => WrWconv_Last,
695	                   vld_o     => WrData_Vld,
696	                   rdy_i => WrData_Rdy,
697	                   dat_o     => WrData_Data,
698	                   last_o    => WrData_Last,
699	                   we_o      => WrData_We);
700	  end generate;
701	  g_nwrite : if not impl_write_g generate
702	    wr_rdy_o <= '0';
703	  end generate;
704	
705	  -- *** Read Releated Code ***
706	  g_read : if impl_read_g generate
707	    -- Read Data FIFO
708	    i_fifo_rd_data : entity work.psi_common_sync_fifo
709	      generic map(width_g        => data_width_g,
710	                  depth_g        => data_fifo_depth_g,
711	                  alm_full_on_g  => false,
712	                  alm_empty_on_g => false,
713	                  ram_style_g    => "auto",
714	                  ram_behavior_g => ram_behavior_g,
715	                  rst_pol_g      => '0'      )
716	      port map(     clk_i => m_axi_aclk,
717	                    rst_i => m_axi_aresetn,
718	                    dat_i => RdFifo_Data,
719	                    vld_i => RdFifo_Vld,
720	                    rdy_o => RdFifo_Rdy,
721	                    dat_o => rd_dat_o,
722	                    vld_o => rd_vld_o,
723	                    rdy_i => rd_rdy_i);
724	  end generate;
725	  g_nread : if not impl_read_g generate
726	    rd_vld_o <= '0';
727	    rd_dat_o <= (others => '0');
728	  end generate;
729	
730	end architecture;

